Customer.getRFQStep = async (req, result) => {
  var token = req.headers.authorization;
  let user_info = await getUserInfo(token)
  let userDetail = await findUserInfoWithEmail(user_info)
  let condition = {
    RFQStep_status: 'Active',
    RFQStep_access_level: userDetail.level
  }
  if (userDetail.level == 'admin') {
    condition = {
      RFQStep_status: 'Active'
    }
  }

  await sql.RFQStep.findAll({
    where: condition
  })
    .then(async (data) => {
      if (data) {
        result(null, data);
      }
    })
    .catch(err => {
      result(err, null);
    });
}

