const Sequelize = require('sequelize');
module.exports = function(sequelize, DataTypes) {
  return sequelize.define('RFQStep', {
    RFQStep_id: {
      autoIncrement: true,
      autoIncrementIdentity: true,
      type: DataTypes.INTEGER,
      allowNull: false,
      primaryKey: true
    },
    RFQStep_title: {
      type: DataTypes.STRING,
      allowNull: true
    },
    RFQStep_status: {
      type: DataTypes.STRING,
      allowNull: true
    },
    RFQStep_access_level: {
      type: DataTypes.STRING,
      allowNull: true
    },
    RFQStep_notified_user_level: {
      type: DataTypes.STRING,
      allowNull: true
    }
  }, {
    sequelize,
    tableName: 'RFQStep',
    schema: process.env.schema,
    timestamps: false,
    indexes: [
      {
        name: "RFQStep_pkey",
        unique: true,
        fields: [
          { name: "RFQStep_id" },
        ]
      },
    ]
  });
};

