import { UntypedFormControl } from '@angular/forms';
import { Observable, Subscription } from 'rxjs';
import { firstValueFrom } from 'rxjs';
import { map, startWith } from 'rxjs/operators';
import { AfterViewInit, Component, OnDestroy, OnInit, ViewChild, ViewContainerRef, ElementRef } from '@angular/core';
import { ICellRendererParams } from "ag-grid-community";
import { AgEditorComponent } from "ag-grid-angular";
import { itemService } from '../../../helpers/services/main.service';
import { MatSelect as MatSelect } from '@angular/material/select';
import { MatAutocompleteTrigger } from '@angular/material/autocomplete';

export interface data {
  value: string;
}
/**
 * rfq-autocompleteComponent
 * created for apply filter on each column
 */

@Component({
    selector: 'rfq-autocomplete',
    templateUrl: 'rfq-autocomplete.component.html',
    styleUrls: ['rfq-autocomplete.component.scss'],
    standalone: false
})
export class rfqAutocompleteComponent implements AgEditorComponent, AfterViewInit, OnDestroy {
  @ViewChild('automcomplete', { read: MatAutocompleteTrigger }) autocomplete: MatAutocompleteTrigger;
  @ViewChild('select', { read: MatSelect }) multipleSelect: MatSelect;
  params: ICellRendererParams;
  private _editorReady = false;
  private _destroyed = false;
  myControl = new UntypedFormControl();
  options: any[] = [];
  multiple = false;
  filteredOptions: Observable<any[]>;
  selectedValues: any[] = [];
  // Synchronous array bound to mat-option @for in the multi-select branch.
  // MUST stay synchronous — see CLAUDE.md mat-select rule #2.
  popupOptions: any[] = [];
  // Titles parsed from params.value in agInit (e.g. "License A,License B").
  // Used after the License/Div data loads to hydrate `selectedValues` with the
  // full option objects so MatSelect's [(ngModel)] starts pre-ticked correctly.
  private _initialTitles: string[] = [];
  private _searchSub?: Subscription;
  masterColumnDefs: any = []
  pc_field_name: any;
  constructor(private itemService: itemService, public elementRef: ElementRef) {
  }

  // compareWith for mat-select [(ngModel)] — match selected objects to options by id.
  // Without this, MatSelect compares by reference and pre-selected values never match
  // the freshly-loaded option objects.
  compareById = (a: any, b: any): boolean => {
    if (a === b) return true;
    if (!a || !b) return false;
    return a.id != null && b.id != null && a.id === b.id;
  };

  ngViewContainerRef() {

  }
  ngAfterViewInit() {
    window['autocomplete'] = this.autocomplete;
    window['multipleSelect'] = this.multipleSelect;

    // License and Div fields use mat-select; their panel is opened after data
    // loads in ngOnInit (see _openMultiSelectWhenReady). Only handle the
    // autocomplete fields here.
    if (this.params.colDef.field === "License" || this.params.colDef.field === "Div") {
      return;
    }

    setTimeout(async () => {
      for (let i = 0; i < 5; i++) {
        if (!this.autocomplete) { return; }
        this.autocomplete.openPanel();
        if (this.autocomplete.panelOpen) {
          break;  // panel is open — stop retrying
        }
        await new Promise(f => setTimeout(f, 100));
      }
    }, 1);
  }

  ngOnDestroy(): void {
    this._destroyed = true;
    this._searchSub?.unsubscribe();
  }

  /**
   * Seeds the synchronous popupOptions array used by the mat-select template,
   * and subscribes to the search input so filtering updates the array directly
   * (no `| async` pipe — see CLAUDE.md mat-select rule #2).
   */
  private _initPopupOptions(): void {
    this.popupOptions = this.options.slice();
    this._searchSub?.unsubscribe();
    this._searchSub = this.myControl.valueChanges.subscribe((value: any) => {
      this.popupOptions = value ? this._filter(value) : this.options.slice();
    });
  }

  /**
   * Opens the mat-select panel once data is ready.
   * Called at the end of each multi-select data-load branch in ngOnInit.
   */
  private _openMultiSelectWhenReady(): void {
    // nextTick: let Angular render the freshly-populated option list before
    // positioning the overlay, so the panel opens with the correct height.
    setTimeout(() => {
      if (!this._destroyed) {
        this.multipleSelect?.open();
      }
    }, 0);
  }
  getMasterFiledName(colId) {
    const colHeaders = window['colHeaders'];
    if (colHeaders) {
      for (var i = 0; colHeaders.length > i; i++) {
        if (colHeaders[i].colId == colId) {
          return colHeaders[i].field;
        }
      }
    }
    for (var i = 0; this.masterColumnDefs.length > i; i++) {
      if (this.masterColumnDefs[i].col_id == colId) {
        return this.masterColumnDefs[i].field;
      }
    }
  }

  agInit(params: any): void {
    this.params = params;
    if (this.params.colDef.field != "License" && this.params.colDef.field != "Div") {
      this.myControl.setValue(params.value)
    } else if (params.value) {
      const rawValue = params.value?.title ?? params.value;
      this._initialTitles = typeof rawValue === 'string'
        ? rawValue.split(",").map((s: string) => s.trim()).filter(Boolean)
        : [];
    }
  }

  // ESC cancels the edit; all other keys are stopped from reaching AG-Grid
  // so it doesn't navigate away while the user is typing in the search field.
  onSearchKeyDown(event: KeyboardEvent): void {
    if (event.key === 'Escape') {
      this.params.api.stopEditing(true);
    } else {
      event.stopPropagation();
    }
  }

  onPanelOpened(): void {
    this._editorReady = true;
  }

  onSelectClosed(): void {
    // _destroyed guard: if AG Grid already called stopEditing (e.g. via Tab or
    // clicking another cell), the component may be mid-destroy; skip to avoid
    // a double stopEditing call.
    if (this._editorReady && !this._destroyed) {
      this.params.api.stopEditing(false);
    }
  }

  /* Component Editor Lifecycle methods */
  // the final value to send to the grid, on completion of editing
  // `selectedValues` is now the single source of truth — mat-select writes to it
  // directly via [(ngModel)], so getValue() always sees the user's latest pick.
  getValue() {
    if (this.selectedValues.length) {
      let licenceTextValue = "";
      for (var i = 0; this.selectedValues.length > i; i++) {
        if (i != this.selectedValues.length - 1) {
          licenceTextValue = this.selectedValues[i].title + "," + licenceTextValue
        } else {
          licenceTextValue = licenceTextValue + this.selectedValues[i].title
        }
      }
      if (this.selectedValues.length == 0) {
        this.selectedValues.push({ item_id: this.params.data.id })
      }
      let highestRoyalty = 0;
      let fobHighestRoyalty = 0;
      for (var i = 0; i < this.selectedValues.length; i++) {
        if (this.selectedValues[i].royalty_rate > highestRoyalty) {
          highestRoyalty = this.selectedValues[i].royalty_rate;
          fobHighestRoyalty = this.selectedValues[i].fob_royalty_rate;
        }
      }
      this.params.data[this.getMasterFiledName('lic_fob_royalty')] = fobHighestRoyalty
      this.params.data[this.getMasterFiledName('lic_whse_royalty')] = highestRoyalty
      this.params.data[this.getMasterFiledName('lic_poe_royalty')] = highestRoyalty
      this.params.data[this.getMasterFiledName('lic_mddp_royalty')] = highestRoyalty
      this.params.data[this.getMasterFiledName('gen_mddp_royalty')] = 0
      this.params.data[this.getMasterFiledName('gen_fob_royalty')] = 0
      this.params.data[this.getMasterFiledName('gen_whse_royalty')] = 0
      this.params.data[this.getMasterFiledName('gen_poe_royalty')] = 0
      this.params.data['royalty'] = highestRoyalty
      const dataSnapshot = this.params.data;
      setTimeout(() => { this.params.api?.applyTransaction({ update: [dataSnapshot] }); }, 0);
      // this.itemService.updateLicense(this.selectedValues).subscribe(data => {
      // })

      return { title: licenceTextValue }
    } else if (this.myControl.value) {
      return this.myControl.value
    }
  }
  async ngOnInit() {
    window['multiple'] = this.multiple;
    if(!window['rfq-autocomplete']) window['rfq-autocomplete'] = {};
        if(!window['rfq-autocomplete'].headers)
        {
          window['rfq-autocomplete'].headers = await firstValueFrom(this.itemService.getGridHeader({ grid_id: 'rfq' }));
        }

        this.masterColumnDefs = window['rfq-autocomplete'].headers;

        this.pc_field_name = this.getMasterFiledName('price_code')
        if (this.params.colDef.field == "Name") {
          try {
            const data: any = await firstValueFrom(this.itemService.getAllVendors());
            for (var i = 0; data.length > i; i++) {
              this.options.push({ title: data[i].vendor_company_nickname, id: data[i].vendor_id })
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
          } catch (err) {
            console.error('[RfqAutocompleteComponent] getAllVendors failed:', err);
          }
        } else if (this.params.colDef.field == "Size (LxW)") {
          try {
            const data: any = await firstValueFrom(this.itemService.getMerchGroup({ divisionCode: 1, DivisionStatus: this.params.data.Status.id }));
            for (var i = 0; data.length > i; i++) {
              for (var j = 0; data[i].merchGroupHeaders.length > j; j++) {
                if (data[i].merchGroupHeaders[j].mgTypeDesc == "Size") {
                  for (var k = 0; data[i].merchGroupHeaders[j].merchGroups.length > k; k++) {
                    this.options.push({ title: data[i].merchGroupHeaders[j].merchGroups[k].mg_desc, id: data[i].merchGroupHeaders[j].merchGroups[k].mg_id})
                  }
                }
              }
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
          } catch (err) {
            console.error('[RfqAutocompleteComponent] id }) failed:', err);
          }
        } else if (this.params.colDef.field == "Chosen Vendor") {
          try {
            const data: any = await firstValueFrom(this.itemService.getAllVendors());
            for (var i = 0; data.length > i; i++) {
              this.options.push({ title: data[i].vendor_company_nickname, id: data[i].vendor_id, item_id: this.params.data.id, email: data[i].vendor_email })
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
          } catch (err) {
            console.error('[RfqAutocompleteComponent] getAllVendors failed:', err);
          }
        } else if (this.params.colDef.field == "Depth") {
          try {
            const data: any = await firstValueFrom(this.itemService.getItemDepth());
            for (var i = 0; data.length > i; i++) {
              this.options.push({ title: data[i].itemDepth_title, id: data[i].itemDepth_id })
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
          } catch (err) {
            console.error('[RfqAutocompleteComponent] getItemDepth failed:', err);
          }
        } else if (this.params.colDef.field == "Customer") {
          try {
            const data: any = await firstValueFrom(this.itemService.getCustomers());
            for (var i = 0; data.length > i; i++) {
              this.options.push({ title: data[i].customers_name, id: data[i].customers_id, dilution: data[i].customers_dilution, logistics_load: data[i].customers_logistic_load, logo: data[i].customers_logo || null })
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
          } catch (err) {
            console.error('[RfqAutocompleteComponent] getCustomers failed:', err);
          }
        } else if (this.params.colDef.field == "RFQ Group") {
          try {
            const data: any = await firstValueFrom(this.itemService.getRFQGroup());
            for (var i = 0; data.length > i; i++) {
              this.options.push({ title: data[i].RFQGroup_name, id: data[i].RFQGroup_id || data[i].id })
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
          } catch (err) {
            console.error('[RfqAutocompleteComponent] getRFQGroup failed:', err);
          }
        } else if (this.params.colDef.field == "License") {
          this.multiple = true;
          window['multiple'] = this.multiple;

          try {
            const data: any = await firstValueFrom(this.itemService.getLicenseList());
            for (var i = 0; data.length > i; i++) {
              const opt = { title: data[i].licenseList_title, id: data[i].licenseList_id, royalty_rate: data[i].licenseList_royalty_rate, item_id: this.params.data.id, fob_royalty_rate: data[i].licenseList_fob_royalty_rate };
              if (this._initialTitles.includes(data[i].licenseList_title)) {
                this.selectedValues.push(opt);
              }
              this.options.push(opt);
            }
            this._initPopupOptions();
            this._openMultiSelectWhenReady();
          } catch (err) {
            console.error('[RfqAutocompleteComponent] getLicenseList failed:', err);
          }
        } else if (this.params.colDef.field == "Delivery Location") {
          try {
            const data: any = await firstValueFrom(this.itemService.getDeliveryLocation());
            for (var i = 0; data.length > i; i++) {
              this.options.push({ title: data[i].deliveryLocation_title, id: data[i].deliveryLocation_id })
            }
            this.filteredOptions = this.myControl.valueChanges.pipe(
              startWith(''),
              map(value => (typeof value === 'string' ? value : value)),
              map(value => (value ? this._filter(value) : this.options.slice())),
            );
