    if (data) {
      if (data.title) {
        return data.title && data.title ? data.title : '';
      } else {
        return data && data ? data : '';
      }
    }
  }

  private _filter(value: any): any[] {
    let filterValue;
    if (value.title) {
      filterValue = value.title.toString().toLowerCase();
    } else {
