const { getContext } = require('../helpers/context.middleware');
var brevoService = require('../helpers/brevo');
const jwt = require("jsonwebtoken");
const { authToken, getUserInfo } = require('./../helpers/auth')
const { vendorMayModifyQuote } = require('../helpers/quote-access')
const privateKey = process.env.JWT_PRIVATE_KEY;
const publicKey = process.env.JWT_PUBLIC_KEY;
const fetch = require('node-fetch');
var STDService = require('../services/std.service');
const emailService = require("../services/email.service")

'use strict';

/**
 * Ownership guard for vendor-facing quote mutations (updateVendor, keepPrice).
 *
 * A vendor JWT carries `factory_id` (see makeSingleToken / login in lib.model.js),
 * and an RFQVendor row's `vendor_id_fk` stores the owning Factory.id. A vendor may
 * only modify a quote that belongs to their own factory. Without this check the
 * sequential integer `quote_id` is enumerable (IDOR): a vendor could POST another
 * factory's quote_id and mutate it.
 *
 * Fail-open cases (returns true) — never block a legitimate user:
 *   - userInfo is missing or the role is not 'vendor' (internal roles unaffected).
 *   - the vendor's token has no factory_id (legacy vendor with no factory link):
 *     ownership can't be verified, so we allow rather than lock them out.
 *   - the quote row has no vendor_id_fk yet.
 *
 * The invite-an-individual-vendor-to-an-item flow is unaffected: the invited
 * vendor is provisioned with their own factory and their own RFQVendor row, so
 * token.factory_id === rfqVendor.vendor_id_fk and this returns true.
 *
 * @param {object|null} userInfo  decoded JWT ({ role, factory_id, ... })
 * @param {object|null} rfqVendor RFQVendor instance/row ({ vendor_id_fk, ... })
 * @returns {boolean} true if the action is allowed
 */
function vendorMayModifyQuote(userInfo, rfqVendor) {
  if (!userInfo || userInfo.role !== 'vendor') return true; // internal roles unaffected
  if (!rfqVendor) return true; // nothing to own; let the caller's not-found path handle it

  const tokenFactoryId = userInfo.factory_id;
  if (tokenFactoryId === null || tokenFactoryId === undefined || tokenFactoryId === '') {
    return true; // null-safe: cannot verify ownership, do not block legacy vendors
  }

  const quoteFactoryId = rfqVendor.vendor_id_fk;
  if (quoteFactoryId === null || quoteFactoryId === undefined || quoteFactoryId === '') {
    return true; // unassigned quote row; nothing to protect
  }

  return String(quoteFactoryId) === String(tokenFactoryId);
}

module.exports = { vendorMayModifyQuote };

