'use strict';

/**
 * De-duplicate RFQ step rows by their title for the Step dropdown.
 *
 * The RFQStep table stores one row per (step, access_level). The same step
 * title can therefore exist for several roles — e.g. "@factories" exists for
 * both `admin` and `production` (ids 3 and 9), and "@sourcing" for both `sales`
 * and `production` (ids 2 and 8). Each row is legitimate: a production-role user
 * needs their own row so the access_level filter in getRFQStep returns it.
 *
 * The problem only surfaces for admins: getRFQStep drops the access_level filter
 * for admin users, so an admin receives every role's row and the Step dropdown
 * shows each shared title twice. Neither the model nor the autocomplete deduped,
 * so the duplicates were rendered verbatim.
 *
 * This collapses duplicate titles, keeping the first occurrence. Callers pass
 * rows ordered by RFQStep_id ASC, so the lowest id wins deterministically. In
 * both real duplicate pairs the kept and dropped rows share the same
 * RFQStep_notified_user_level, so notifications are unaffected.
 *
 * Non-admin callers only ever receive rows for their single access_level, so
 * their lists contain no duplicate titles and pass through unchanged.
 *
 * @param {Array<{RFQStep_title?: string}>} rows Sequelize instances or plain objects.
 * @returns {Array} rows with duplicate titles removed, original order preserved.
 */
function dedupeRfqStepsByTitle(rows) {
  if (!Array.isArray(rows)) return [];
  const seen = new Set();
  return rows.filter((row) => {
    const title = row && row.RFQStep_title;
    if (title === null || title === undefined) return true; // keep untitled rows untouched
    if (seen.has(title)) return false;
    seen.add(title);
    return true;
  });
}

module.exports = { dedupeRfqStepsByTitle };

