const { describe, test, expect } = require('@jest/globals');
const { dedupeRfqStepsByTitle } = require('../../helpers/rfqStepDedupe');

// Mirrors the real designflow_dev RFQStep table: "@factories" and "@sourcing"
// each exist for two roles, which an admin (no access_level filter) receives in
// full. Rows arrive ordered by RFQStep_id ASC, as getRFQStep requests.
const ADMIN_ROWS = [
  { RFQStep_id: 1, RFQStep_title: '@sales for details', RFQStep_access_level: 'designer' },
  { RFQStep_id: 2, RFQStep_title: '@sourcing', RFQStep_access_level: 'sales' },
  { RFQStep_id: 3, RFQStep_title: '@factories', RFQStep_access_level: 'admin' },
  { RFQStep_id: 4, RFQStep_title: 'px sent to sales', RFQStep_access_level: 'admin' },
  { RFQStep_id: 7, RFQStep_title: 'px sent to cust', RFQStep_access_level: 'sales' },
  { RFQStep_id: 8, RFQStep_title: '@sourcing', RFQStep_access_level: 'production' },
  { RFQStep_id: 9, RFQStep_title: '@factories', RFQStep_access_level: 'production' },
  { RFQStep_id: 10, RFQStep_title: 'For Later', RFQStep_access_level: 'sales' },
];

describe('dedupeRfqStepsByTitle', () => {
  test('collapses duplicate titles an admin sees across roles', () => {
    const result = dedupeRfqStepsByTitle(ADMIN_ROWS);
    const titles = result.map((r) => r.RFQStep_title);
    expect(titles).toEqual([
      '@sales for details',
      '@sourcing',
      '@factories',
      'px sent to sales',
      'px sent to cust',
      'For Later',
    ]);
  });

  test('reduces the admin list from 8 rows to 6 distinct steps', () => {
    expect(dedupeRfqStepsByTitle(ADMIN_ROWS)).toHaveLength(6);
  });

  test('keeps the lowest RFQStep_id for each duplicated title', () => {
    const byTitle = Object.fromEntries(
      dedupeRfqStepsByTitle(ADMIN_ROWS).map((r) => [r.RFQStep_title, r.RFQStep_id]),
    );
    expect(byTitle['@factories']).toBe(3); // not 9
    expect(byTitle['@sourcing']).toBe(2); // not 8
  });

  test('leaves a non-admin (single access_level) list unchanged', () => {
    // A production user is filtered to their own rows — no duplicate titles.
    const productionRows = [
      { RFQStep_id: 8, RFQStep_title: '@sourcing', RFQStep_access_level: 'production' },
      { RFQStep_id: 9, RFQStep_title: '@factories', RFQStep_access_level: 'production' },
    ];
    expect(dedupeRfqStepsByTitle(productionRows)).toEqual(productionRows);
  });

  test('returns an empty array for non-array input', () => {
    expect(dedupeRfqStepsByTitle(null)).toEqual([]);
    expect(dedupeRfqStepsByTitle(undefined)).toEqual([]);
  });

  test('keeps rows that have no title rather than collapsing them', () => {
    const rows = [
      { RFQStep_id: 1 },
      { RFQStep_id: 2 },
      { RFQStep_id: 3, RFQStep_title: 'Active step' },
    ];
    expect(dedupeRfqStepsByTitle(rows)).toHaveLength(3);
  });
});

